#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        if(N==2){
            printf("-1\n");
            continue;
        }
        if(N%2==1){
            for(int i=1;i<=N;i++){
                if(i>1) printf(" ");
                printf("%d",i);
            }
            printf("\n");
        }else{
            // even N >=4
            printf("1 %d",N);
            for(int i=2;i<N;i++) printf(" %d",i);
            printf("\n");
        }
    }
    return 0;
}

