#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        if N == 2:
            out_lines.append("-1")
            continue
        if N % 2 == 1:
            out_lines.append(' '.join(str(i) for i in range(1, N+1)))
        else:
            seq = [1, N] + list(range(2, N))
            out_lines.append(' '.join(map(str, seq)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

